import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Download, Trash2 } from 'lucide-react';
import { reportsApi } from '../api/reports';
import { exportApi } from '../api/export';
import DataTable from '../components/DataTable';
import MonthFilter from '../components/MonthFilter';
import FileImport from '../components/FileImport';
import Card from '../components/Card';
import MonthlyComparison from '../components/MonthlyComparison';
import WeeklyComparison from '../components/WeeklyComparison';
import BestMonthAnalysis from '../components/BestMonthAnalysis';
import MarketingStrategyAdvisor from '../components/MarketingStrategyAdvisor';

const Labs: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'data' | 'strategy'>('data');
  const [selectedMonth, setSelectedMonth] = useState('');

  const { data: reports = [], isLoading: reportsLoading } = useQuery({
    queryKey: ['reports', selectedMonth],
    queryFn: () => reportsApi.getReports(selectedMonth ? { month: selectedMonth } : undefined),
  });

  // Extract unique months from reports
  const availableMonths = React.useMemo(() => {
    const months = new Set<string>();
    reports.forEach(report => {
      const date = new Date(report.report_date);
      const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      months.add(monthKey);
    });
    return Array.from(months).sort().reverse();
  }, [reports]);

  const handleClearAll = () => {
    const confirmed = window.confirm(
      'Are you sure you want to clear all data? This action cannot be undone.'
    );
    if (confirmed) {
      // Handle clear all - would need mutation here
      console.log('Clear all data');
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <h1 className="text-2xl font-bold text-gray-900 mb-8">Action Labs</h1>

      {/* Tab Navigation */}
      <div className="border-b border-gray-200 mb-8">
        <nav className="-mb-px flex space-x-8">
          <button
            onClick={() => setActiveTab('data')}
            className={`py-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'data'
                ? 'border-primary-500 text-primary-600'
                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            Data Entry
          </button>
          <button
            onClick={() => setActiveTab('strategy')}
            className={`py-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'strategy'
                ? 'border-primary-500 text-primary-600'
                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            Strategy View
          </button>
        </nav>
      </div>

      {/* Data Entry Tab */}
      {activeTab === 'data' && (
        <div className="space-y-6">
          {/* Header Actions */}
          <Card>
            <div className="flex flex-wrap items-center justify-between gap-4">
              <h2 className="text-lg font-semibold text-gray-900">Data Management</h2>
              
              <div className="flex flex-wrap items-center gap-4">
                <FileImport />
                
                <a
                  href={exportApi.exportCsv()}
                  className="btn-secondary inline-flex items-center"
                >
                  <Download className="w-4 h-4 mr-2" />
                  Export CSV
                </a>
                
                <button
                  onClick={handleClearAll}
                  className="btn-danger inline-flex items-center"
                >
                  <Trash2 className="w-4 h-4 mr-2" />
                  Clear All Data
                </button>
              </div>
            </div>
          </Card>

          {/* Controls */}
          <Card>
            <div className="flex items-center justify-between">
              <MonthFilter
                value={selectedMonth}
                onChange={setSelectedMonth}
                months={availableMonths}
                loading={reportsLoading}
              />
              
              <div className="text-sm text-gray-600">
                {reports.length} record{reports.length !== 1 ? 's' : ''} found
              </div>
            </div>
          </Card>

          {/* Data Table */}
          <DataTable
            data={reports}
            loading={reportsLoading}
            onView={(report) => {
              alert(JSON.stringify(report, null, 2));
            }}
            onEdit={(report) => {
              console.log('Edit report:', report);
              // Would open edit modal here
            }}
          />
        </div>
      )}

      {/* Strategy View Tab */}
      {activeTab === 'strategy' && (
        <div className="space-y-8">
          {/* Page Header */}
          <div className="bg-gradient-to-r from-blue-600 to-purple-600 text-white p-6 rounded-lg">
            <h2 className="text-xl font-bold mb-2">Action Labs – Strategy View (Detailed)</h2>
            <p className="text-blue-100">
              Comprehensive analytics with Monthly Comparison, Weekly Analysis, Best Month Detection, and AI-powered Marketing Strategy Advisor.
            </p>
          </div>

          {/* Monthly Comparison Module */}
          <section>
            <MonthlyComparison />
          </section>

          {/* Weekly Comparison Module */}
          <section>
            <WeeklyComparison />
          </section>

          {/* Best Month Analysis Module */}
          <section>
            <BestMonthAnalysis />
          </section>

          {/* Marketing Strategy Advisor Module */}
          <section>
            <MarketingStrategyAdvisor />
          </section>
        </div>
      )}
    </div>
  );
};

export default Labs;
